You want to implement a caching system where each index file has its own cache, and this cache is not shared with other index files. This is often referred to as a "per-cache" or "per-index" cache.

Here's a high-level example of how you could implement this using a dictionary to store the cache for each index file:

```python
import os

class IndexCache:
    def __init__(self, cache_dir):
        self.cache_dir = cache_dir
        self.caches = {}

    def get_cache(self, index_file):
        if index_file not in self.caches:
            cache_path = os.path.join(self.cache_dir, f"{os.path.basename(index_file)}.cache")
            self.caches[index_file] = {}
            if not os.path.exists(cache_path):
                os.makedirs(cache_path)
        return self.caches[index_file]

    def set(self, index_file, key, value):
        cache = self.get_cache(index_file)
        cache[key] = value

    def get(self, index_file, key):
        cache = self.get_cache(index_file)
        return cache.get(key)

    def delete(self, index_file, key):
        cache = self.get_cache(index_file)
        if key in cache:
            del cache

